commands.cmd:
flag=/var/run/reboot-required
pkgs_file=/var/run/reboot-required.pkgs
if [ ! -e "$flag" ]; then
  printf '{"reboot_required":false,"reason":"","pkgs":""}'
else
  reason=$(cat "$flag" 2>/dev/null) || { echo "reboot-required unreadable" >&2; exit 1; }
  if [ -e "$pkgs_file" ]; then
    pkgs=$(cat "$pkgs_file" 2>/dev/null) || { echo "reboot-required.pkgs unreadable" >&2; exit 1; }
  else
    pkgs=""
  fi
  printf '%s\n%s' "$reason" "$pkgs" | awk '
    NR==1{r=$0; next}
    {p=(p=="" ? $0 : p " " $0)}
    END{
      gsub(/\\/,"\\\\",r); gsub(/"/,"\\\"",r);
      gsub(/\\/,"\\\\",p); gsub(/"/,"\\\"",p);
      printf "{\"reboot_required\":true,\"reason\":\"%s\",\"pkgs\":\"%s\"}", r, p
    }' || exit 1
fi
